class Solution:
	def insertion(self, nums: list[int], index: int) -> None:
		if index == len(nums) - 1:
			return
		self.insertion(nums, index + 1)
		if nums[index] > nums[index + 1]:
			self.swap(nums, index, index + 1)

	def swap(self, nums: list[int], i: int, j: int) -> None:
		nums[i], nums[j] = nums[j], nums[i]

	def heapify(self, nums: list[int], n: int, i: int) -> None:
		if i >= n:
			return
		if i >= (n // 2):
			return
		if nums[i] > nums[0]:
			self.heapify(nums, n, 0)

	def solve(self, nums: list[int]) -> bool:
		self.heapify(nums, len(nums), 0)
		return True

