# include <bits/stdc++.h>
using namespace std;
class Solution {
public:
	bool solve(vector<int>& nums) {
		heapify(nums, nums.size(), 0);
		return true;
	}
private:
	void heapify(vector<int>& nums, int n, int i) {
		if (i >= n) return;
		if (i >= (n / 2)) return;
		if (nums[i] > nums[0]) {
			heapify(nums, n, 0);
		}
	}
};
int main() {
	int n;
	cin >> n;
	vector<int> nums(n);
	for (int i = 0; i < n; i++) cin >> nums[i];
	Solution solution;
	cout << (solution.solve(nums) ? 'true' : 'false') << endl;
	return 0;
}
